using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationMetricsResponse
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<PerClassMetrics> PerClassMetrics { get; set; } = new();
}

public class PerClassMetrics
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetricsResponse _metrics;
    private readonly string[] _classNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Extract class names for confidence mapping
        var categories = _mlContext.Data
            .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
            .Select(t => t.Category)
            .Distinct()
            .OrderBy(c => c)
            .ToArray();
        _classNames = categories;

        // Build the pipeline: combine text features, add priority, then classify
        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on all data and evaluate via cross-validation
        _model = pipeline.Fit(dataView);

        var crossValResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
        var avgMetrics = crossValResults.First().Metrics;

        _metrics = new EvaluationMetricsResponse
        {
            MacroAccuracy = (float)crossValResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = (float)crossValResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = (float)crossValResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = (float)crossValResults.Average(r => r.Metrics.LogLossReduction),
            PerClassMetrics = avgMetrics.PerClassLogLoss
                .Select((logLoss, i) => new PerClassMetrics
                {
                    ClassName = i < _classNames.Length ? _classNames[i] : $"Class{i}",
                    Precision = i < avgMetrics.ConfusionMatrix.PerClassPrecision.Count
                        ? avgMetrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < avgMetrics.ConfusionMatrix.PerClassRecall.Count
                        ? avgMetrics.ConfusionMatrix.PerClassRecall[i] : 0,
                    F1Score = CalculateF1(
                        i < avgMetrics.ConfusionMatrix.PerClassPrecision.Count
                            ? avgMetrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                        i < avgMetrics.ConfusionMatrix.PerClassRecall.Count
                            ? avgMetrics.ConfusionMatrix.PerClassRecall[i] : 0)
                }).ToList()
        };

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _classNames.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classNames[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationMetricsResponse GetMetrics() => _metrics;

    private static double CalculateF1(double precision, double recall) =>
        precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

